1	//! REST API for non-MCP agents.
2	//!
3	//! Mounted at `/api/v1/`. Provides simple HTTP endpoints for agents
4	//! that don't speak MCP. All endpoints require an API key.
5	
6	use axum::response::Json;
7	use serde_json::{json, Value};
8	
9	use crate::client::InternalClient;
10	
11	/// Shared REST API state.
12	#[derive(Clone)]
13	pub struct ApiRouter {
14	    client: InternalClient,
15	}
16	
17	impl ApiRouter {
18	    pub const fn new(client: InternalClient) -> Self {
19	        Self { client }
20	    }
21	
22	    /// Health check — no auth required.
23	    pub async fn health(&self) -> Json<Value> {
24	        Json(json!({
25	            "status": "ok",
26	            "version": env!("CARGO_PKG_VERSION"),
27	            "gateway": "ans-gateway"
28	        }))
29	    }
30	
31	    /// POST /api/v1/sessions — create a new browser session.
32	    pub async fn create_session(&self, body: Value) -> Json<Value> {
33	        let goal_id = body.get("goal_id").and_then(|v| v.as_str()).unwrap_or("");
34	        let start_url = body
35	            .get("start_url")
36	            .and_then(|v| v.as_str())
37	            .unwrap_or("about:blank");
38	
39	        let mut client = self.client.clone_client();
40	        let req = tonic::Request::new(ans_proto::ans::CreateSessionRequest {
41	            goal_id: goal_id.into(),
42	            start_url: start_url.into(),
43	            headers: std::collections::HashMap::new(),
44	        });
45	
46	        match client.create_session(req).await {
47	            Ok(resp) => {
48	                let r = resp.into_inner();
49	                Json(json!({
50	                    "session_id": r.session_id,
51	                    "goal_id": r.goal_id,
52	                    "status": r.status,
53	                    "created_at": r.created_at,
54	                    "last_activity_at": r.last_activity_at,
55	                }))
56	            }
57	            Err(e) => Json(json!({
58	                "error": format!("gRPC error: {}", e)
59	            })),
60	        }
61	    }
62	
63	    /// POST /api/v1/sessions/:id/navigate — navigate browser to URL.
64	    pub async fn navigate(&self, session_id: &str, body: Value) -> Json<Value> {
65	        let url = body
66	            .get("url")
67	            .and_then(|v| v.as_str())
68	            .unwrap_or("about:blank");
69	
70	        let mut client = self.client.clone_client();
71	        let req = tonic::Request::new(ans_proto::ans::NavigateRequest {
72	            session_id: session_id.into(),
73	            url: url.into(),
74	            timeout_ms: 30000,
75	        });
76	
77	        match client.navigate(req).await {
78	            Ok(resp) => {
79	                let r = resp.into_inner();
80	                Json(json!({
81	                    "session_id": session_id,
82	                    "url": r.url,
83	                    "title": r.title,
84	                    "loaded": r.loaded,
85	                    "dom_node_count": r.dom_node_count,
86	                }))
87	            }
88	            Err(e) => Json(json!({
89	                "error": format!("gRPC error: {}", e)
90	            })),
91	        }
92	    }
93	
94	    /// POST /api/v1/sessions/:id/execute — execute a browser action.
95	    pub async fn execute_action(&self, session_id: &str, body: Value) -> Json<Value> {
96	        let action_type = body
97	            .get("action_type")
98	            .and_then(|v| v.as_str())
99	            .unwrap_or("click");
100	        let selector = body.get("selector").and_then(|v| v.as_str()).unwrap_or("");
101	        let value = body.get("value").and_then(|v| v.as_str()).unwrap_or("");
102	
103	        let mut client = self.client.clone_client();
104	        let req = tonic::Request::new(ans_proto::ans::ExecuteActionRequest {
105	            session_id: session_id.into(),
106	            action: Some(ans_proto::ans::Action {
107	                action_type: action_type.into(),
108	                selector: selector.into(),
109	                value: value.into(),
110	                params: std::collections::HashMap::new(),
111	            }),
112	        });
113	
114	        match client.execute_action(req).await {
115	            Ok(resp) => {
116	                let r = resp.into_inner();
117	                Json(json!({
118	                    "session_id": session_id,
119	                    "success": r.success,
120	                    "error_message": r.error_message,
121	                    "execution_time_ms": r.execution_time_ms,
122	                }))
123	            }
124	            Err(e) => Json(json!({
125	                "error": format!("gRPC error: {}", e)
126	            })),
127	        }
128	    }
129	
130	    /// POST /api/v1/sessions/:id/screenshot — capture screenshot.
131	    pub async fn screenshot(&self, session_id: &str, body: Value) -> Json<Value> {
132	        let full_page = body
133	            .get("full_page")
134	            .and_then(serde_json::Value::as_bool)
135	            .unwrap_or(false);
136	        let format = body.get("format").and_then(|v| v.as_str()).unwrap_or("png");
137	
138	        let mut client = self.client.clone_client();
139	        let req = tonic::Request::new(ans_proto::ans::ScreenshotRequest {
140	            session_id: session_id.into(),
141	            format: format.into(),
142	            quality: 80,
143	            full_page,
144	            arrow_shm_key: String::new(),
145	        });
146	
147	        match client.capture_screenshot(req).await {
148	            Ok(resp) => {
149	                let r = resp.into_inner();
150	                Json(json!({
151	                    "session_id": session_id,
152	                    "success": r.success,
153	                    "format": r.format,
154	                    "size_bytes": r.size_bytes,
155	                    "data_base64_len": r.data.len(),
156	                }))
157	            }
158	            Err(e) => Json(json!({
159	                "error": format!("gRPC error: {}", e)
160	            })),
161	        }
162	    }
163	
164	    /// GET /api/v1/sessions/:id/dom — get distilled DOM.
165	    pub async fn get_dom(&self, session_id: &str) -> Json<Value> {
166	        let mut client = self.client.clone_client();
167	        let req = tonic::Request::new(ans_proto::ans::DomRequest {
168	            session_id: session_id.into(),
169	            mode: "input_fields".into(),
170	        });
171	
172	        match client.get_distilled_dom(req).await {
173	            Ok(resp) => {
174	                let r = resp.into_inner();
175	                Json(json!({
176	                    "session_id": session_id,
177	                    "mode": r.mode,
178	                    "url": r.url,
179	                    "title": r.title,
180	                    "element_count": r.elements.len(),
181	                    "interactive_count": r.interactive.len(),
182	                    "semantic_block_count": r.semantic_blocks.len(),
183	                }))
184	            }
185	            Err(e) => Json(json!({
186	                "error": format!("gRPC error: {}", e)
187	            })),
188	        }
189	    }
190	
191	    /// GET /api/v1/goals/:id — get goal state.
192	    pub async fn get_goal(&self, goal_id: &str) -> Json<Value> {
193	        let mut client = self.client.clone_client();
194	        let req = tonic::Request::new(ans_proto::ans::GoalStateRequest {
195	            goal_id: goal_id.into(),
196	        });
197	
198	        match client.get_goal_state(req).await {
199	            Ok(resp) => {
200	                let r = resp.into_inner();
201	                Json(json!({
202	                    "goal_id": r.goal_id,
203	                    "description": r.description,
204	                    "status": r.status,
205	                    "progress": r.progress,
206	                    "sub_goals": r.sub_goals.len(),
207	                    "created_at": r.created_at,
208	                }))
209	            }
210	            Err(e) => Json(json!({
211	                "error": format!("gRPC error: {}", e)
212	            })),
213	        }
214	    }
215	
216	    /// POST /api/v1/goals — create a new goal.
217	    pub async fn create_goal(&self, body: Value) -> Json<Value> {
218	        let description = body
219	            .get("description")
220	            .and_then(|v| v.as_str())
221	            .unwrap_or("");
222	        let context_str = body.get("context").and_then(|v| v.as_str()).unwrap_or("");
223	        let max_steps = body
224	            .get("max_steps")
225	            .and_then(serde_json::Value::as_i64)
226	            .unwrap_or(100) as i32;
227	
228	        let mut context = std::collections::HashMap::new();
229	        if !context_str.is_empty() {
230	            context.insert("context".into(), context_str.into());
231	        }
232	
233	        let mut client = self.client.clone_client();
234	        let req = tonic::Request::new(ans_proto::ans::CreateGoalRequest {
235	            description: description.into(),
236	            context,
237	            max_budget_cents: 500,
238	            max_steps,
239	        });
240	
241	        match client.create_goal(req).await {
242	            Ok(resp) => {
243	                let r = resp.into_inner();
244	                Json(json!({
245	                    "goal_id": r.goal_id,
246	                    "description": r.description,
247	                    "status": r.status,
248	                    "progress": r.progress,
249	                }))
250	            }
251	            Err(e) => Json(json!({
252	                "error": format!("gRPC error: {}", e)
253	            })),
254	        }
255	    }
256	}
