1	//! Model Context Protocol (MCP) server — JSON-RPC over HTTP.
2	//!
3	//! Exposes the Agent Nervous System as MCP tools for Claude, `ChatGPT`,
4	//! and other MCP-compatible AI agents.
5	//!
6	//! Specification: <https://spec.modelcontextprotocol.io>
7	
8	use serde_json::{json, Value};
9	
10	use crate::client::InternalClient;
11	
12	const MCP_VERSION: &str = "2024-11-05";
13	
14	/// MCP server state shared across requests.
15	#[derive(Clone)]
16	pub struct McpServer {
17	    client: InternalClient,
18	}
19	
20	impl McpServer {
21	    pub const fn new(client: InternalClient) -> Self {
22	        Self { client }
23	    }
24	
25	    /// Handle an incoming JSON-RPC request. Returns the JSON-RPC response.
26	    pub async fn handle_request(&self, body: Value) -> Value {
27	        let id = body.get("id").cloned();
28	        let method = body.get("method").and_then(|m| m.as_str()).unwrap_or("");
29	
30	        match method {
31	            "initialize" => self.handle_initialize(id),
32	            "tools/list" => self.handle_tools_list(id),
33	            "tools/call" => self.handle_tools_call(id, &body).await,
34	            _ => json_rpc_error(id, -32601, &format!("Method not found: {method}")),
35	        }
36	    }
37	
38	    fn handle_initialize(&self, id: Option<Value>) -> Value {
39	        json_rpc_result(
40	            id,
41	            json!({
42	                "protocolVersion": MCP_VERSION,
43	                "serverInfo": {
44	                    "name": "agent-nervous-system",
45	                    "version": env!("CARGO_PKG_VERSION")
46	                },
47	                "capabilities": {
48	                    "tools": {}
49	                }
50	            }),
51	        )
52	    }
53	
54	    fn handle_tools_list(&self, id: Option<Value>) -> Value {
55	        json_rpc_result(
56	            id,
57	            json!({
58	                "tools": [
59	                    {
60	                        "name": "create_session",
61	                        "description": "Create a new browser session for an agent goal",
62	                        "inputSchema": {
63	                            "type": "object",
64	                            "properties": {
65	                                "goal_id": { "type": "string", "description": "Goal ID this session belongs to" },
66	                                "start_url": { "type": "string", "description": "Initial URL to load (default: about:blank)" }
67	                            },
68	                            "required": ["goal_id"]
69	                        }
70	                    },
71	                    {
72	                        "name": "navigate",
73	                        "description": "Navigate the browser to a URL",
74	                        "inputSchema": {
