## 3. Dashboard UI: Data Flow

### Connection Lifecycle

```
Dashboard loads
    │
    ├── GET /            → HTML delivered (include_str!)
    ├── GET /dashboard.css → CSS delivered
    ├── GET /dashboard.js  → JS delivered
    │
    ├── JS: connect WebSocket ws://127.0.0.1:50052/ws
    │   │
    │   ├── On open: receive {type: "connected", version: "..."}
    │   │
    │   ├── On message: handle event
    │   │   ├── {type: "goal_update", goal_id, progress, status, message}
    │   │   ├── {type: "eye_report", goal_id, eye_name, confidence, content}
    │   │   ├── {type: "action_log", goal_id, action_type, selector, value,
    │   │   │                                   success, elapsed_ms}
    │   │   └── {type: "goal_complete", goal_id, success, summary, steps, cost}
    │   │
    │   └── Send: {type: "subscribe", goal_id: "..."}  (client-side filter)
    │
    └── JS: no initial REST fetch needed -- state is streamed
```

### Message Protocol (WebSocket JSON)

All messages are JSON with a `type` field. Defined as a TypeScript interface for clarity:

```typescript
// ── Server → Client ────────────────────────────

interface WelcomeMessage {
  type: "connected";
  version: string;
  message: string;
}

interface GoalUpdateMessage {
  type: "goal_update";
  goal_id: string;
  progress: number;       // 0.0 - 1.0
  status: "pending" | "active" | "completed" | "failed" | "blocked";
  message: string;
  sub_goals?: SubGoal[];
}

interface EyeReportMessage {
  type: "eye_report";
  goal_id: string;
  eye_name: "dom_reader" | "vision" | "page_diff" | "goal_verifier" | "error_detector";
  confidence: number;     // 0.0 - 1.0
  content: string;        // human-readable summary text
  details?: object;       // structured data when available
}

interface ActionLogMessage {
  type: "action_log";
  goal_id: string;
  step: number;
  timestamp: number;      // epoch ms
  action_type: string;
  selector: string;
  value: string;
  success: boolean;
  execution_time_ms: number;
  page_url_after?: string;
  error?: string;
}

interface GoalCompleteMessage {
  type: "goal_complete";
  goal_id: string;
  success: boolean;
  summary: string;
  total_steps: number;
  sub_goals_completed: number;
  total_sub_goals: number;
  total_cost_cents: number;
  elapsed_seconds: number;
}

interface ErrorMessage {
  type: "error";
  goal_id?: string;
  message: string;
}

// ── Client → Server ────────────────────────────

interface SubscribeMessage {
  type: "subscribe";
  goal_id: string;
}

interface UnsubscribeMessage {
  type: "unsubscribe";
  goal_id: string;
}

// Only goal_update, eye_report, action_log, and goal_complete
// for the subscribed goal_id are forwarded. Others are silently
// dropped by the server-side filter.
```

