```javascript
// ── Module: WebSocketClient ────────────
// Manages connection lifecycle, reconnection, message routing

class WebSocketClient {
  constructor(url, messageHandler) {
    this.url = url;
    this.handler = messageHandler;
    this.ws = null;
    this.reconnectDelay = 1000;
    this.maxReconnectDelay = 30000;
    this.connect();
  }

  connect() {
    this.ws = new WebSocket(this.url);
    this.ws.onopen = () => {
      AppState.connected = true;
      updateConnectionStatus(true);
      // Re-subscribe if had an active goal
      if (AppState.currentGoalId) {
        this.send({ type: "subscribe", goal_id: AppState.currentGoalId });
      }
    };
    this.ws.onmessage = (event) => {
      const msg = JSON.parse(event.data);
      this.handler(msg);
    };
    this.ws.onclose = () => {
      AppState.connected = false;
      updateConnectionStatus(false);
      // Exponential backoff reconnect
      setTimeout(() => this.connect(), this.reconnectDelay);
      this.reconnectDelay = Math.min(
        this.reconnectDelay * 2, this.maxReconnectDelay
      );
    };
  }

  send(msg) {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify(msg));
    }
  }
}

// ── Module: GoalSubmit ────────────
// Handles the goal input textarea and submit button

async function submitGoal() {
  const description = document.getElementById("goalInput").value.trim();
  if (!description) return;

  // Disable submit button, show loading
  setSubmitState("loading");

  try {
    const resp = await fetch("/api/v1/goals", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ description, mode: AppState.mode }),
    });
    const data = await resp.json();
    if (data.error) throw new Error(data.error);

    AppState.currentGoalId = data.goal_id;
    wsClient.send({ type: "subscribe", goal_id: data.goal_id });

    // Show progress section, hide previous result
    showSection("progressSection");
    hideSection("resultSection");
    showSection("eyesSection");
    showSection("logSection");
    resetState(data);
    startTimer();
  } catch (err) {
    showError(err.message);
    setSubmitState("idle");
  }
}

// ── Module: MessageRouter ────────────
// Routes incoming WS messages to the right renderer

function handleMessage(msg) {
  switch (msg.type) {
    case "connected":
      console.log("ANS connected", msg.version);
      break;

    case "goal_update":
      updateProgress(msg);
      if (msg.sub_goals) updateSubGoals(msg.sub_goals);
      break;

    case "eye_report":
      updateEyeReport(msg);
      break;

    case "action_log":
      appendActionLog(msg);
      break;

    case "goal_complete":
      showResult(msg);
      stopTimer();
      setSubmitState("idle");
      break;

    case "error":
      showError(msg.message);
      break;
  }
}

