  };
  // Create/update accordion row
  const cfg = eyeConfig[msg.eye_name] || { icon: "❓", color: "gray" };
  // ... render row with mini confidence bar
}

function appendActionLog(msg) {
  const log = document.getElementById("logEntries");
  const entry = document.createElement("div");
  entry.className = `log-entry ${msg.success ? "success" : "failure"}`;
  entry.innerHTML = `
    <span class="log-time">${formatTime(msg.timestamp)}</span>
